// Validate input
const body = $input.first().json.body || $input.first().json;
const niche = body.niche?.trim();
if (!niche || niche.length < 2) {
  throw new Error('Niche name is required (min 2 characters)');
}

return [{
  json: {
    niche,
    description: body.description?.trim() || '',
    target_video_count: parseInt(body.target_video_count, 10) || 25,
    channel_style: '2hr_documentary'
  }
}];

// Extract project from Supabase response (returns array)
const response = $input.first().json;
const project = Array.isArray(response) ? response[0] : response;
if (!project?.id) {
  throw new Error('Failed to create project — no ID returned');
}
return [{ json: { project_id: project.id, niche: project.niche, description: project.niche_description || '' } }];

// Parse Claude's niche research response
const response = $input.first().json;

// Check for API error
if (response.error) {
  throw new Error(`Anthropic API error: ${response.error.message || JSON.stringify(response.error)}`);
}

// Extract text content from response
const textBlocks = (response.content || []).filter(c => c.type === 'text');
const rawText = textBlocks.map(c => c.text).join('');

// Strip markdown code fences if present
let jsonText = rawText.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();

// Find the JSON object
const jsonStart = jsonText.indexOf('{');
const jsonEnd = jsonText.lastIndexOf('}');
if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON found in Claude response');
}
jsonText = jsonText.substring(jsonStart, jsonEnd + 1);

let research;
try {
  research = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`Failed to parse research JSON: ${e.message}`);
}

// Pass through project context + parsed research
return [{
  json: {
    project_id: $('Extract Project ID').first().json.project_id,
    niche: $('Extract Project ID').first().json.niche,
    description: $('Extract Project ID').first().json.description,
    research,
    competitor_analysis: research.competitor_analysis || {},
    audience_pain_points: research.audience_pain_points || {},
    keyword_research: research.keyword_research || {},
    blue_ocean_opportunities: research.blue_ocean_opportunities || {},
    expertise_profile: research.expertise_profile || '',
    system_prompt: research.system_prompt || '',
    playlist_angles: research.playlist_angles || [],
    red_ocean_topics: research.red_ocean_topics || [],
    audience_psychographic: research.audience_psychographic || ''
  }
}];

